// User is the resolver for the user field.
func (r *viewerResolver) User(ctx context.Context, obj *appmodel.Viewer) (*db.User, error) {
	// cases can just set the userID to the viewer
	userID := obj.UserID

	// if it not set, we can try to get it from the token
	if userID == nil && obj.UserToken != nil {
		v := int64(obj.UserToken.ID)
		userID = &v
	}

	if userID != nil {
		user, err := r.env(ctx).UserByID(ctx, *userID)
		if err != nil {
			if errors.Is(err, sql.ErrNoRows) {
				return nil, nil
			}

			return nil, err
		}

		return &user, nil
	}

	return nil, nil
}

